function parseProspectsFromAI(text,agentId){const prospects=[];const sections=text.split(/###\s*\d+\.\s*/);for(let i=1;i<sections.length;i++){const s=sections[i];const nameM=s.match(/\*\*(.+?)\*\*/);const emailM=s.match(/[\w.-]+@[\w.-]+\.[a-z]{2,}/i);const phoneM=s.match(/\+?[\d\s()-]{8,}/);const webM=s.match(/(?:Website|website)[^:]*:\s*([\w.-]+\.\w+)/i);const igM=s.match(/@([\w.]+)/);const contactM=s.match(/(?:Decision Maker|Contact|Director)[^:]*:\s*(.+?)(?:\n|$)/i);const titleM=s.match(/(?:Marketing Director|Brand Manager|Head of|CMO|CEO|Director|Manager|Owner)[\w\s]*/i);if(nameM){prospects.push({id:Date.now()+i,name:nameM[1].trim(),website:webM?webM[1]:"",ind:"",stage:"Research",contactName:contactM?contactM[1].trim():"",contactTitle:titleM?titleM[0].trim():"",email:emailM?emailM[0]:"",phone:phoneM?phoneM[0].trim():"",ig:igM?"@"+igM[1]:"",linkedin:"",val:0,notes:s.slice(0,300),assignedTo:agentId,logs:[{type:"note",date:new Date().toLocaleDateString("en-US",{month:"short",day:"numeric"}),msg:"Auto-discovered by AI agent",direction:"inbound"}],requirements:{},date:"TBD",venue:"",hours:0,editedVideos:0,videoDuration:"",guests:0,additionalNotes:""});}}return prospects;}
