  // âââ NANO BANANA (Gemini) IMAGE GENERATION âââ
  async function generateImage(prompt){
    if(!apiKeys.gemini)return{error:"No Gemini API key. Go to Integrations â add your key."};
    try{
      const r=await fetch(`https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash-exp:generateContent?key=${apiKeys.gemini}`,{
        method:"POST",headers:{"Content-Type":"application/json"},
        body:JSON.stringify({contents:[{parts:[{text:`Generate an image: ${prompt}`}]}],generationConfig:{responseModalities:["IMAGE","TEXT"]}})
      });
      const d=await r.json();
      if(d.error)return{error:d.error.message||"Gemini API error"};
      const imgPart=d.candidates?.[0]?.content?.parts?.find(p=>p.inlineData);
      if(imgPart)return{image:`data:${imgPart.inlineData.mimeType};base64,${imgPart.inlineData.data}`};
      const textPart=d.candidates?.[0]?.content?.parts?.find(p=>p.text);
      return{error:textPart?.text||"No image returned. Try a different prompt."};
    }catch(e){return{error:e.message};}
  }

  // âââ PHONE CALLS (Vapi primary, Bland.ai fallback) âââ
  async function makeCall(phone,script,agentName,agentId){
    if(apiKeys.vapi){return makeVapiCall(phone,script,agentName,agentId);}
    if(!apiKeys.bland)return{error:"No Vapi or Bland.ai API key. Go to Integrations â add your key."};
    try{
      const r=await fetch("https://api.bland.ai/v1/calls",{
        method:"POST",headers:{"Authorization":apiKeys.bland,"Content-Type":"application/json"},
        body:JSON.stringify({phone_number:phone,task:script,voice:"maya",reduce_latency:true,from:apiKeys.blandPhone||undefined,webhook:null})
      });
      const d=await r.json();
      if(d.status==="success"||d.call_id)return{success:true,callId:d.call_id,msg:`Call initiated to ${phone}. Call ID: ${d.call_id}`};
      return{error:d.message||"Call failed"};
    }catch(e){return{error:e.message};}
  }

  // âââ OPENAI TTS â text-to-speech with per-agent voice âââ
  async function speakText(text,agentId){
    const voiceName=VOICE_MAP[agentId]||"alloy";
    const key=apiKeys.openai;
    if(!key)return{error:"No OpenAI API key. Go to Integrations â add your key."};
    try{
      const r=await fetch("https://api.openai.com/v1/audio/speech",{
        method:"POST",headers:{"Authorization":`Bearer ${key}`,"Content-Type":"application/json"},
        body:JSON.stringify({model:"tts-1",input:text.slice(0,4096),voice:voiceName,response_format:"mp3"})
      });
      if(!r.ok){const e=await r.json();return{error:e.error?.message||"TTS failed"};}
      const blob=await r.blob();
      const url=URL.createObjectURL(blob);
      const audio=new Audio(url);
      audio.play();
      return{success:true,url,voice:voiceName};
    }catch(e){return{error:e.message};}
  }

  // âââ VAPI PHONE CALLS âââ
  async function makeVapiCall(phone,script,agentName,agentId){
    const key=apiKeys.vapi;
    if(!key)return{error:"No Vapi API key. Go to Integrations â add your key."};
    const voiceName=VOICE_MAP[agentId]||"alloy";
    try{
      const r=await fetch("https://api.vapi.ai/call/phone",{
        method:"POST",headers:{"Authorization":`Bearer ${key}`,"Content-Type":"application/json"},
        body:JSON.stringify({assistantOverrides:{firstMessage:`Hi, this is ${agentName} from Kapturise.`,model:{provider:"openai",model:"gpt-4o",messages:[{role:"system",content:script}]},voice:{provider:"openai",voiceId:voiceName}},customer:{number:phone}})
      });
      const d=await r.json();
      if(d.id)return{success:true,callId:d.id,msg:`Vapi call initiated to ${phone}. Call ID: ${d.id}`};
      return{error:d.message||JSON.stringify(d)};
    }catch(e){return{error:e.message};}
  }

  // âââ CRM EXPORT âââ
  function exportLeadsCSV(){
    const headers=["Company","Industry","Stage","Contact","Title","Email","Phone","Instagram","Website","Value","Assigned Agent","Service","Source"];
    const rows=leads.map(l=>[l.name,l.ind,l.stage,l.contactName,l.contactTitle,l.email,l.phone,l.ig,l.website,l.val,agents.find(a=>a.id===l.assignedTo)?.name||"",pricing.find(p=>p.id===l.serviceType)?.name||"",l.src].map(v=>`"${(v||"").toString().replace(/"/g,'""')}"`).join(","));
    const csv=[headers.join(","),...rows].join("\n");
    const blob=new Blob([csv],{type:"text/csv"});
    const url=URL.createObjectURL(blob);
    const a=document.createElement("a");a.href=url;a.download=`kapturise-leads-${new Date().toISOString().split("T")[0]}.csv`;a.click();URL.revokeObjectURL(url);
  }

