        {camp.emailScript&&<div style={{background:T.sa,borderRadius:6,padding:8,marginBottom:6}}><div style={{fontSize:10,color:T.br,marginBottom:3}}>âï¸ Email Script</div><div style={{fontSize:11.5,color:T.ts,whiteSpace:"pre-wrap"}}>{camp.emailScript}</div></div>}
