        {camp.contentBrief&&<div style={{background:T.sa,borderRadius:6,padding:8,marginBottom:6}}><div style={{fontSize:10,color:T.vi,marginBottom:3}}>ð¢ Content Brief</div><div style={{fontSize:11.5,color:T.ts,whiteSpace:"pre-wrap"}}>{camp.contentBrief}</div></div>}
        {camp.url&&<div style={{fontSize:11,color:T.sk,marginBottom:4}}>ð {camp.url}</div>}
