  // âââ TEAM VIEW âââ
  function TeamView({role}){const def=ROLES[role];const team=agents.filter(a=>a.role===role);const c=T[def.color];
    const[showAdd,setShowAdd]=useState(false);
    const[na,setNa]=useState({name:"",title:"",av:"ð¤",pic:"",eth:"",bg:""});
    const addAg=()=>{if(!na.name)return;const newId=na.name.toLowerCase().replace(/\s/g,"-")+"-"+Date.now();setAgents(p=>[...p,{id:newId,name:na.name,role,title:na.title,av:na.av,pic:na.pic||`https://ui-avatars.com/api/?name=${encodeURIComponent(na.name)}&background=e8401e&color=fff&size=150&bold=true`,eth:na.eth,bg:na.bg,status:"active",config:agent_cfg_for_role(role)}]);setNa({name:"",title:"",av:"ð¤",pic:"",eth:"",bg:""});setShowAdd(false);};
    return <div>
      <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:14}}>
        <span style={{fontSize:22}}>{def.icon}</span>
        <div style={{flex:1}}><h2 style={{fontSize:17,fontWeight:700,margin:0}}>{def.label} Team</h2><p style={{fontSize:12,color:T.ts,margin:0}}>{team.length} agents</p></div>
        <button style={bt(c)} onClick={()=>setShowAdd(!showAdd)}>+ Add Agent</button>
      </div>
      {showAdd&&<div style={cd}>
        <div style={{fontSize:12.5,fontWeight:600,marginBottom:10}}>New {def.label} Agent</div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>
          <input style={ip} placeholder="Full Name (e.g. Fatima Al-Zahra)" value={na.name} onChange={e=>setNa({...na,name:e.target.value})} />
          <input style={ip} placeholder="Title (e.g. Senior Closer)" value={na.title} onChange={e=>setNa({...na,title:e.target.value})} />
          <input style={ip} placeholder="Avatar emoji (e.g. ð©âð¼)" value={na.av} onChange={e=>setNa({...na,av:e.target.value})} />
          <input style={ip} placeholder="Photo URL (optional â auto-generated if blank)" value={na.pic} onChange={e=>setNa({...na,pic:e.target.value})} />
          <input style={ip} placeholder="Ethnicity (e.g. Emirati)" value={na.eth} onChange={e=>setNa({...na,eth:e.target.value})} />
        </div>
        <input style={{...ip,marginTop:8}} placeholder="Background & specialty (e.g. Luxury brands, 5yrs DIFC)" value={na.bg} onChange={e=>setNa({...na,bg:e.target.value})} />
        <div style={{display:"flex",gap:7,marginTop:10}}><button style={bt(c)} onClick={addAg}>Create Agent</button><button style={btG(T.td)} onClick={()=>setShowAdd(false)}>Cancel</button></div>
      </div>}
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
        {team.map(a=><div key={a.id} style={{...cd,display:"flex",alignItems:"center",gap:10,opacity:a.status==="paused"?0.6:1}}>
          <div style={{cursor:"pointer",display:"flex",alignItems:"center",gap:10,flex:1}} onClick={()=>setView(`a:${a.id}`)}
            onMouseOver={e=>e.currentTarget.parentElement.style.borderColor=c} onMouseOut={e=>e.currentTarget.parentElement.style.borderColor=T.bd}>
            <Av a={a} size={40} /><div style={{flex:1}}><div style={{fontSize:13,fontWeight:600}}>{a.name}</div><div style={{fontSize:11,color:T.ts}}>{a.title}</div><div style={{fontSize:10,color:T.td}}>{(a.config||DEF_CFG).targeting.industries.slice(0,3).join(", ")}</div></div>
          </div>
          <div style={{display:"flex",flexDirection:"column",gap:3,alignItems:"flex-end"}}>
            <span style={{...bdg(a.status==="active"?T.em:T.am),fontSize:9,cursor:"pointer"}} onClick={()=>setAgents(p=>p.map(x=>x.id===a.id?{...x,status:x.status==="active"?"paused":"active"}:x))}><span style={dot(a.status==="active"?T.em:T.am)} /> {a.status==="active"?"Active":"Paused"}</span>
            <button style={{background:"transparent",border:`1px solid ${T.bd}`,borderRadius:4,padding:"2px 6px",fontSize:9,color:T.ts,cursor:"pointer",fontFamily:F.d}} onClick={(e)=>{e.stopPropagation();const newName=prompt("Name for cloned agent:",`${a.name} (Copy)`);if(newName){const nid=newName.toLowerCase().replace(/\s/g,"-")+"-"+Date.now();setAgents(p=>[...p,{...a,id:nid,name:newName,pic:`https://ui-avatars.com/api/?name=${encodeURIComponent(newName)}&background=e8401e&color=fff&size=150&bold=true`}]);}}}>ð Clone</button>
          </div>
        </div>)}
      </div>
    </div>;
  }

  // âââ RENDER âââ
  const render=()=>{
    if(view==="dashboard")return <Dash/>;if(view==="leads")return <CRM/>;if(view==="pricing")return <PricingPage/>;
    if(view==="social")return <SocialPage/>;if(view==="campaigns")return <CampaignsPage/>;if(view==="scripts")return <ScriptsPage/>;if(view==="investors")return <InvestorPipeline/>;if(view==="followups")return <FollowUpPage/>;if(view==="social-outreach")return <SocialOutreachPage/>;if(view==="proposals")return <ProposalsPage/>;if(view==="integrations")return <IntPage/>;
    if(view==="agents")return <AllAgents/>;if(view==="company")return CompanyPage();if(view==="brand")return BrandPage();if(view==="skills")return <SkillsPage/>;
    if(view.startsWith("t:"))return <TeamView role={view.slice(2)}/>;
    if(view.startsWith("a:")){const ag=agents.find(a=>a.id===view.slice(2));if(ag)return <AgentWork agent={ag} agents={agents} setAgents={setAgents} scripts={scripts} isApproached={isApproached} markApproached={markApproached} scoreProspect={scoreProspect} autoCreateFollowUp={autoCreateFollowUp}/>;}return null;
  };

